import type { AppSettings } from '~/types/appSettings'

import { createDefu } from 'defu'

const customDefu = createDefu((obj, key, value) => {
  if (Array.isArray(value) && value.every((x: any) => typeof x === 'string')) {
    obj[key] = value
    return true
  }
})

const defaultAppSettings: AppSettings = {
  sidebar: {
    collapsible: 'offcanvas',
    side: 'left',
    variant: 'sidebar',
  },
  theme: {
    color: 'default',
    type: 'default',
  },
}

export function useAppSettings() {
  const { appSettings } = useAppConfig()

  const processedConfig = customDefu(appSettings, defaultAppSettings)

  const cookieAppSettings = useCookie<AppSettings>('app_settings', {
    default: () => processedConfig,
  })

  const updateAppSettings = (settings: AppSettings) => {
    cookieAppSettings.value = customDefu(settings, cookieAppSettings.value)
  }

  return {
    updateAppSettings,
    sidebar: computed(() => cookieAppSettings.value.sidebar),
    theme: computed(() => cookieAppSettings.value.theme),
  }
}

import { defineTask, useRuntimeConfig } from 'nitropack/runtime'
import { lt } from 'drizzle-orm'
// @ts-expect-error nuxthub/db is a virtual module provided by @nuxthub/core
import { db, schema } from '@nuxthub/db'
import { parseRetention } from '../utils/retention'
import type { RuntimeConfigWithEvlog } from '../../config'

export default defineTask({
  meta: {
    name: 'evlog:cleanup',
    description: 'Clean up expired evlog events based on retention policy',
  },
  async run() {
    const config = useRuntimeConfig() as RuntimeConfigWithEvlog
    const retention = config.evlog?.retention ?? '7d'
    const { totalMs } = parseRetention(retention)
    const cutoff = new Date(Date.now() - totalMs).toISOString()

    try {
      const result = await db.delete(schema.evlogEvents)
        .where(lt(schema.evlogEvents.createdAt, cutoff))

      console.log(`[evlog/nuxthub] Cleanup: deleted events older than ${retention} (before ${cutoff})`, result)
      return { result: 'success' }
    } catch (error) {
      console.error('[evlog/nuxthub] Cleanup task failed:', error)
      return { result: 'error' }
    }
  },
})

export default defineNuxtPlugin(() => {
  const timer = useState('timer', () => 0)

  if (import.meta.client) {
    let timerRunning = false
    addRouteMiddleware(async () => {
      if (timerRunning) return

      console.log('Starting timer...')
      timerRunning = true
      timer.value = 5

      do {
        await new Promise(resolve => setTimeout(resolve, 100))
        console.log('Timer:', timer.value)
        timer.value--
      } while (timer.value > 0)

      console.log('...and navigating')
      timerRunning = false
    })
  }

  addRouteMiddleware((to) => {
    if (to.path === '/forbidden') {
      return false
    }
  })

  addRouteMiddleware((to) => {
    const { $config } = useNuxtApp()
    if ($config) {
      console.log('Accessed runtime config within middleware.')
    }

    if (to.path !== '/redirect') {
      return
    }

    console.log('Heading to', to.path, 'but I think we should go somewhere else...')
    return '/secret'
  })
})

import { defineEventHandler, createError } from 'h3'
import { resolveSecurityRules } from '../../nitro/context'
import type { HTTPMethod } from '../../../types/middlewares'

export default defineEventHandler((event) => {
  const rules = resolveSecurityRules(event)

  if (rules.enabled && rules.allowedMethodsRestricter) {
    const { allowedMethodsRestricter } = rules

    const allowedMethods = allowedMethodsRestricter.methods

    if (allowedMethods !== '*' && !allowedMethods.includes(event.node.req.method! as HTTPMethod)) {
      const methodNotAllowedError = {
        statusCode: 405,
        statusMessage: 'Method not allowed'
      }

      if (allowedMethodsRestricter.throwError === false) {
        return methodNotAllowedError
      }
      throw createError(methodNotAllowedError)
    }
  }
})

import type { RefreshableScheme, HTTPResponse } from '../types'
import type { Auth } from '../core'

export class RefreshController {
  public $auth: Auth
  private _refreshPromise: Promise<HTTPResponse | void> = null

  constructor(public scheme: RefreshableScheme) {
    this.$auth = scheme.$auth
  }

  // Multiple requests will be queued until the first has completed token refresh.
  handleRefresh(): Promise<HTTPResponse | void> {
    // Another request has started refreshing the token, wait for it to complete
    if (this._refreshPromise) {
      return this._refreshPromise
    }

    return this._doRefresh()
  }

  // Returns a promise which is resolved when refresh is completed
  // Call this function when you intercept a request with an expired token.

  private _doRefresh(): Promise<HTTPResponse | void> {
    this._refreshPromise = new Promise((resolve, reject) => {
      this.scheme
        .refreshTokens()
        .then((response) => {
          this._refreshPromise = null
          resolve(response)
        })
        .catch((error) => {
          this._refreshPromise = null
          reject(error)
        })
    })

    return this._refreshPromise
  }
}

import { useDevtoolsClient } from '@nuxt/devtools-kit/iframe-client'

export function findClosestTraceInfo(el: Element) {
  const client = useDevtoolsClient().value
  if (!client || !client.host.inspector) {
    throw new Error('`findClosestWithTraceInfo` must be used when the devtools client is connected')
  }
  const { findTraceFromElement } = client.host.nuxt.__tracerRecord

  const traceInfo = findTraceFromElement(el)
  if (!traceInfo && el.parentElement) {
    return findClosestTraceInfo(el.parentElement)
  }
  return traceInfo
}

export function openElementSourceComponent(el: Element) {
  const client = useDevtoolsClient().value
  if (!client || !client.host.inspector) {
    throw new Error('`openElementSourceComponent` must be used when the devtools client is connected')
  }

  const { findTraceFromElement } = client.host.nuxt.__tracerRecord

  const traceInfo = findTraceFromElement(el)
  if (!traceInfo && el.parentElement) {
    return openElementSourceComponent(el.parentElement)
  }
  if (traceInfo) {
    client.devtools.rpc.openInEditor(traceInfo.filepath)
  }
  console.info('[@nuxt/hints] Source component not found for element', el)
}

import { resolve } from 'node:path'
import { defineCommand, runMain } from 'citty'
import type { CLIOptions } from './types'

export function createCLI(opts: CLIOptions) {
  const main = defineCommand({
    meta: {
      name: opts.name,
      description: opts.description,
    },
    args: {
      dir: {
        type: 'positional',
        description: 'Project directory',
        required: false,
        default: 'docs',
      },
      template: {
        type: 'string',
        alias: 't',
        description: 'Template to use (default, i18n)',
        required: false,
        default: 'default',
      },
    },
    async setup(context) {
      const dir = resolve(context.args.dir as string)
      const template = context.args.template as 'i18n' | 'default'

      if (!['i18n', 'default'].includes(template)) {
        throw new Error('Invalid template')
      }

      const { runCommand } = await import('@nuxt/cli')
      await runCommand('init', [dir, '-t', `gh:nuxt-content/docus/.starters/${template}`])
    },
  })

  return {
    runMain: () => runMain(main),
  }
}

import type { OgImageRenderEventContext, VNode, VNodeTransformer } from '../../../types'

export function walkTree(e: OgImageRenderEventContext, node: VNode, plugins: (VNodeTransformer | VNodeTransformer[])[]) {
  const promises: (Promise<void> | void)[] = []

  // Apply plugins to the current node
  for (const plugin of plugins.flat()) {
    if (plugin.filter(node)) {
      promises.push(plugin.transform(node, e))
    }
  }

  // If node has no children or they're not an array, we're done with this branch
  if (!node.props?.children || !Array.isArray(node.props.children))
    return promises

  // remove empty children
  if (node.props.children.length === 0) {
    delete node.props.children
    return promises
  }

  // walk tree of child nodes (only recurse into VNodes, not strings)
  for (const child of node.props.children || []) {
    if (child && typeof child === 'object') {
      promises.push(
        ...walkTree(e, child, plugins),
      )
    }
  }
  return promises
}

export function defineTransformer(transformer: VNodeTransformer | VNodeTransformer[]) {
  return transformer
}

