type HotEvent = (event: 'nuxt-content:update', callback: (data: { collection: string, key: string, queries: string[] }) => void) => void
export default defineNuxtPlugin(() => {
  if (!import.meta.hot || !import.meta.client) return

  import('../internal/database.client').then(({ loadDatabaseAdapter }) => {
    ;(import.meta.hot as unknown as { on: HotEvent }).on('nuxt-content:update', async (data) => {
      if (!data || !data.collection || !Array.isArray(data.queries)) return
      try {
        const db = await loadDatabaseAdapter(data.collection)
        for (const sql of data.queries) {
          try {
            await db.exec(sql)
          }
          catch (err) {
            console.log(err)
          }
        }
        refreshNuxtData()
      }
      catch {
        // ignore
      }
    })
  })
})

import type { State } from 'mdast-util-to-hast'
import type { Element, Text, Properties } from 'hast'
import type { InlineCode } from 'mdast'

export default function inlineCode(state: State, node: InlineCode & { attributes?: Properties }) {
  const language = node.attributes?.language || node.attributes?.lang
  const text: Text = { type: 'text', value: node.value.replace(/\r?\n|\r/g, ' ') }
  state.patch(node, text)

  const result: Element = {
    type: 'element',
    tagName: 'code',
    properties: node.attributes || {},
    children: [text],
  }

  const classes = (result.properties.class as string || '').split(' ')
  delete result.properties.class

  if (language) {
    result.properties.language = language
    delete result.properties.lang

    classes.push('language-' + language)
  }

  result.properties.className = classes.join(' ')

  state.patch(node, result)
  return state.applyData(node, result)
}

import type { Plugin } from 'vite'
import type { EvlogViteOptions } from './types'

export function createAutoInitPlugin(options: EvlogViteOptions): Plugin {
  const config = buildConfig(options)

  return {
    name: 'evlog:auto-init',
    config() {
      return {
        define: {
          __EVLOG_CONFIG__: JSON.stringify(config),
        },
      }
    },
  }
}

function buildConfig(options: EvlogViteOptions): Record<string, unknown> {
  const env: Record<string, unknown> = {}
  if (options.service) env.service = options.service
  if (options.environment) env.environment = options.environment

  const config: Record<string, unknown> = {}
  if (Object.keys(env).length > 0) config.env = env
  if (options.enabled !== undefined) config.enabled = options.enabled
  if (options.pretty !== undefined) config.pretty = options.pretty
  if (options.silent !== undefined) config.silent = options.silent
  if (options.sampling) config.sampling = options.sampling
  if (options.minLevel !== undefined) config.minLevel = options.minLevel
  if (options.stringify !== undefined) config.stringify = options.stringify

  return config
}

import "#nitro/virtual/polyfills";
import type { fetch } from "@cloudflare/workers-types";
