import { isPublicAssetURL } from "#nitro/virtual/public-assets";
import { createHandler } from "./_module-handler.ts";
import { resolveWebsocketHooks } from "#nitro/runtime/app";

const ws = import.meta._websocket ? wsAdapter({ resolve: resolveWebsocketHooks }) : undefined;

interface Env {
  ASSETS?: { fetch: typeof fetch };
}

export default createHandler<Env>({
  fetch(cfRequest, env, context, url) {
    // Static assets fallback (optional binding)
    if (env.ASSETS && isPublicAssetURL(url.pathname)) {
      return env.ASSETS.fetch(cfRequest as any);
    }

    // Websocket upgrade
    // https://crossws.unjs.io/adapters/cloudflare
    if (import.meta._websocket && cfRequest.headers.get("upgrade") === "websocket") {
      return ws!.handleUpgrade(cfRequest, env, context);
    }
  },
});

import { useNuxt, addVitePlugin } from '@nuxt/kit'

export default async function installPlugin(nuxt = useNuxt()) {
  if (nuxt.options.builder === '@nuxt/vite-builder') {
    const existsTailwindPlugin = (plugins = nuxt.options.vite.plugins): boolean => !!plugins?.some((plugin) => {
      if (Array.isArray(plugin)) {
        return existsTailwindPlugin(plugin)
      }

      return plugin && 'name' in plugin && plugin.name.startsWith('@tailwindcss/vite')
    })

    if (!existsTailwindPlugin()) {
      await import('@tailwindcss/vite').then(r => addVitePlugin(r.default()))
    }
  }
  else {
    nuxt.options.postcss ??= { plugins: {}, order: [] }
    nuxt.options.postcss.plugins ??= {}

    if (!nuxt.options.postcss.plugins['@tailwindcss/postcss']) {
      nuxt.options.postcss.plugins['@tailwindcss/postcss'] = {}
    }
  }
}

import { computed } from 'vue'
import type { SessionLastRefreshedAt, SessionStatus } from '../types'
import { useState } from '#imports'

export function makeCommonAuthState<SessionData>() {
  const data = useState<SessionData | undefined | null>('auth:data', () => undefined)

  const hasInitialSession = computed(() => !!data.value)

  // If session exists, initialize as already synced
  const lastRefreshedAt = useState<SessionLastRefreshedAt>('auth:lastRefreshedAt', () => {
    if (hasInitialSession.value) {
      return new Date()
    }

    return undefined
  })

  // If session exists, initialize as not loading
  const loading = useState<boolean>('auth:loading', () => false)
  const status = computed<SessionStatus>(() => {
    if (loading.value) {
      return 'loading'
    }
    if (data.value) {
      return 'authenticated'
    }
    return 'unauthenticated'
  })

  return {
    data,
    loading,
    lastRefreshedAt,
    status,
  }
}

import type { CollectionInfo } from '@nuxt/content'
import contentManifest from '#content/manifest'

export function refineContentFields<T>(sql: string, doc: T) {
  const fields = findCollectionFields(sql)
  const item = { ...doc } as T
  for (const key in item) {
    if (fields[key as string] === 'json' && item[key] && item[key] !== 'undefined') {
      item[key] = JSON.parse(item[key] as string)
    }
    if (fields[key as string] === 'boolean' && item[key] !== 'undefined') {
      item[key] = Boolean(item[key]) as never
    }
  }

  for (const key in item) {
    if (item[key] === 'NULL') {
      item[key as keyof T] = undefined as unknown as T[keyof T]
    }
  }
  return item
}

function findCollectionFields(sql: string): Record<string, 'string' | 'number' | 'boolean' | 'date' | 'json'> {
  const table = sql.match(/FROM\s+(\w+)/)
  if (!table) {
    return {}
  }

  const info = contentManifest[getCollectionName(table[1]!) as keyof typeof contentManifest] as CollectionInfo
  return info?.fields || {}
}

function getCollectionName(table: string) {
  return table.replace(/^_content_/, '')
}

